    public function handle_file_upload() {
        if (!isset($_POST['user_file_upload_nonce']) || !isset($_POST['user_id'])) {
            wp_die('Invalid request');
        }
        
        $user_id = intval($_POST['user_id']);
        
        if (!wp_verify_nonce($_POST['user_file_upload_nonce'], 'user_file_upload_' . $user_id)) {
            wp_die('Security check failed');
        }
        
        if (!current_user_can('edit_user', $user_id)) {
            wp_die('You do not have permission to upload files for this user');
        }
        
        if (!isset($_FILES['user_file']) || $_FILES['user_file']['error'] !== UPLOAD_ERR_OK) {
            wp_redirect(add_query_arg('upload_error', 'file_error', wp_get_referer()));
            exit;
        }
        
        $file = $_FILES['user_file'];
        $file_type = isset($_POST['file_type']) ? sanitize_text_field($_POST['file_type']) : 'document';
        
        $allowed_types = array(
            'image/jpeg',
            'image/jpg',
            'image/png',
            'image/gif',
            'application/pdf',
            'application/msword',
            'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
        );
        
        $file_mime_type = mime_content_type($file['tmp_name']);
        
        if (!in_array($file_mime_type, $allowed_types)) {
            wp_redirect(add_query_arg('upload_error', 'invalid_type', wp_get_referer()));
            exit;
        }
        
        $max_size = 10 * 1024 * 1024; // 10MB
        if ($file['size'] > $max_size) {
            wp_redirect(add_query_arg('upload_error', 'file_too_large', wp_get_referer()));
            exit;
        }
        
        $user_upload_dir = $this->upload_dir . $user_id . '/';
        if (!file_exists($user_upload_dir)) {
            wp_mkdir_p($user_upload_dir);
        }
        
        $file_extension = pathinfo($file['name'], PATHINFO_EXTENSION);
        $file_name = sanitize_file_name(pathinfo($file['name'], PATHINFO_FILENAME));
        $unique_file_name = $file_name . '_' . time() . '.' . $file_extension;
        $destination = $user_upload_dir . $unique_file_name;
        
        if (move_uploaded_file($file['tmp_name'], $destination)) {
            $relative_path = $user_id . '/' . $unique_file_name;
            
            if ($file_type === 'profile_picture') {
                $old_picture = get_user_meta($user_id, 'user_profile_picture', true);
                if ($old_picture && file_exists($this->upload_dir . $old_picture)) {
                    unlink($this->upload_dir . $old_picture);
                }
                update_user_meta($user_id, 'user_profile_picture', $relative_path);
            } else {
                $documents = get_user_meta($user_id, 'user_documents', true);
                if (!is_array($documents)) {
                    $documents = array();
                }
                $documents[] = $relative_path;
                update_user_meta($user_id, 'user_documents', $documents);
            }
            
            wp_redirect(add_query_arg('upload_success', '1', wp_get_referer()));
            exit;
        } else {
            wp_redirect(add_query_arg('upload_error', 'move_failed', wp_get_referer()));
            exit;
        }
    }
    
    private function get_file_url($relative_path) {
        return content_url('uploads/user-files/' . $relative_path);
    }
    
